+/* =========================================
+   main.css — Base styles, variables, layout
+   ========================================= */
+
+:root {
+  --bg: #0a0a0a;
+  --bg2: #111;
+  --bg3: #1a1a1a;
+  --red: #e50914;
+  --red2: #b81213;
