+  flex-shrink: 0;        /* เพิ่ม — ไม่ให้หด */
+}
+.btn-topup:hover { background: var(--red3); transform: translateY(-1px); box-shadow: 0 4px 18px var(--glow); }
+
+.btn-ghost {
